import { initWeaviateClient, fetchMemoryWithAllProperties } from './src/database/weaviate/client.js';
import { getDocument } from './src/database/firestore/init.js';
import { getMemoryIndexPath } from './src/database/firestore/paths.js';

const uuid = '9b0a86d7-63e7-4d1f-b92a-c66ca6661605';
const indexDoc = await getDocument\(getMemoryIndexPath\(\), uuid\);
const collectionName = indexDoc.collection_name;
const client = await initWeaviateClient\({
  url: process.env.WEAVIATE_REST_URL,
  apiKey: process.env.WEAVIATE_API_KEY,
  openaiApiKey: process.env.OPENAI_API_KEY,
}\);
const collection = client.collections.get\(collectionName\);
const obj = await fetchMemoryWithAllProperties\(collection, uuid\);
const props = obj.properties;
console.log\('follow_up:', JSON.stringify\(props.follow_up\)\);
console.log\('All keys:', Object.keys\(props\).sort\(\).join\(', '\)\);
process.exit\(0\);
" 2>&1)

